  if (s.includes("(Feed generated")) {
    postContent = s.split("(Feed generated")[0].trim();
  }

  return {
    json: {
      название_канала: CHANNEL_NAME,
      название_поста: t || "",
      контент_поста: postContent || "",
      ссылка_на_пост: item.json.link || ""
    }
  };
});

