const items = $input.all();

const formattedPosts = items.map((item, index) => {
  const data = item.json;

  const cleanContent = (data.контент_поста || "")
    .replace(/\n\s*\n/g, '\n')
    .replace(/\s+/g, ' ')   
    .trim();

  return `ПОСТ ${index + 1}:
Канал: ${data.название_канала || "Неизвестный канал"}
Заголовок: ${data.название_поста || "Без заголовка"}
Содержание: ${cleanContent || "Нет описания"}
Ссылка: ${data.ссылка_на_пост || "Нет ссылки"}`;
}).join('\n\n---\n\n');

const aiInput = `Вот сегодняшние посты из Telegram-каналов:

${formattedPosts}`;

return [{
  json: {
    ai_input: aiInput,
    raw_data: items.map(item => item.json),
    posts_count: items.length,
    channels: [...new Set(items.map(item => item.json.название_канала))].filter(Boolean)
  }
}];

function findData(items) {
  let aiOutput = "";
  let rawData = [];

  items.forEach(item => {
    const json = item.json || {};
    if (json.output) aiOutput = json.output;
    if (json.raw_data && Array.isArray(json.raw_data)) rawData = json.raw_data;
  });

  return { aiOutput, rawData };
}

const { aiOutput, rawData } = findData(items);

if (!aiOutput || rawData.length === 0) {
  return [{ json: { error: "Нет данных" } }];
}

// Парсим вывод ИИ
const aiBlocks = aiOutput.trim().split(/\n\s*\n/);
let generalSummary = "";
const aiPosts = [];

aiBlocks.forEach(block => {
  if (block.startsWith('0.')) {
    generalSummary = block.replace('0.', '').replace(/\n/g, ' ').trim();
  } else if (block.match(/^\d+\.\s/)) {
    const lines = block.split('\n').filter(l => l.trim());
    if (lines.length >= 1) {
      const firstLine = lines[0];
      const match = firstLine.match(/^(\d+)\.\s+(.+)$/);
      if (match) {
        const [, number, title] = match;
        const description = lines.slice(1).join(' ').trim();
        aiPosts.push({
          number: parseInt(number),
          title: title.trim(),
          description: description
        });
      }
    }
  }
});

const channelPosts = {};
rawData.forEach((post, index) => {
  const channel = post.название_канала;
  if (!channelPosts[channel]) channelPosts[channel] = [];

  const aiPost = aiPosts[index];

  channelPosts[channel].push({
    title: aiPost ? aiPost.title : post.название_поста,
    description: aiPost ? aiPost.description : (post.контент_поста || "").substring(0, 120) + "...",
    link: post.ссылка_на_пост
  });
});

function escapeUnderscoresInLink(link) {
  if (!link) return "";
  return link.replace(/_/g, '\\_');
}

let digest = "📰 ЕЖЕДНЕВНЫЙ ДАЙДЖЕСТ IT-НОВОСТЕЙ 📰\n\n";

digest += `✨ ${generalSummary || "Обзор IT-новостей"}\n\n`;

Object.entries(channelPosts).forEach(([channel, posts]) => {
  digest += `${channel} - ${posts.length} пост${posts.length > 1 ? 'а' : ''}\n\n`;

  posts.forEach((post, index) => {
    digest += `${index + 1}. ${post.title}\n`;

    if (post.description) {
      digest += `   📝 ${post.description}\n`;
    }

    const escapedLink = escapeUnderscoresInLink(post.link);
    digest += `   🔗 ${escapedLink}\n\n`;
  });
});

const totalPosts = rawData.length;
const totalChannels = Object.keys(channelPosts).length;

digest += `\n📊 Всего: ${totalPosts} материал${totalPosts === 1 ? '' : (totalPosts >= 2 && totalPosts <= 4 ? 'а' : 'ов')} из ${totalChannels} источник${totalChannels === 1 ? 'а' : 'ов'}\n`;
digest += "💻 Полезного дня! #ITновости #Аналитика";

return [{
  json: {
    digest: digest,
  }
}];
